const express = require('express');
const jwt = require('jsonwebtoken');
const fs = require('fs');

const JWT_PUBLIC_KEY = process.env.JWT_PUBLIC_KEY || fs.readFileSync(process.env.JWT_PUBLIC_KEY_PATH || './keys/public.pem', 'utf8');
const JWT_SECRET = process.env.JWT_SECRET;
const JWT_ALGORITHM = process.env.JWT_ALGORITHM || 'RS256';
const JWT_ISSUER = process.env.JWT_ISSUER || 'your-api-issuer';
const JWT_AUDIENCE = process.env.JWT_AUDIENCE || 'your-api-audience';

const ALLOWED_ALGORITHMS = ['RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512'];

const verifyOptions = {
  algorithms: [JWT_ALGORITHM],
  issuer: JWT_ISSUER,
  audience: JWT_AUDIENCE,
  clockTolerance: 30,
  complete: false
};

function getVerificationKey() {
  if (JWT_ALGORITHM.startsWith('RS') || JWT_ALGORITHM.startsWith('ES')) {
    return JWT_PUBLIC_KEY;
  }
  return JWT_SECRET;
}

const authMiddleware = (req, res, next) => {
  const authHeader = req.headers.authorization;

  if (!authHeader) {
    return res.status(401).json({ error: 'No authorization header provided' });
  }

  const parts = authHeader.split(' ');
  
  if (parts.length !== 2 || parts[0] !== 'Bearer') {
    return res.status(401).json({ error: 'Invalid authorization header format' });
  }

  const token = parts[1];

  if (!token) {
    return res.status(401).json({ error: 'No token provided' });
  }

  try {
    const verificationKey = getVerificationKey();
    
    const decoded = jwt.verify(token, verificationKey, verifyOptions);

    if (!decoded.exp) {
      return res.status(401).json({ error: 'Token missing expiration claim' });
    }

    req.user = {
      id: decoded.sub || decoded.userId,
      email: decoded.email,
      roles: decoded.roles || [],
      permissions: decoded.permissions || [],
      ...decoded
    };

    next();
  } catch (error) {
    if (error.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token expired' });
    }
    
    if (error.name === 'JsonWebTokenError') {
      return res.status(401).json({ error: 'Invalid token' });
    }
    
    if (error.name === 'NotBeforeError') {
      return res.status(401).json({ error: 'Token not yet valid' });
    }

    return res.status(401).json({ error: 'Authentication failed' });
  }
};

const optionalAuthMiddleware = (req, res, next) => {
  const authHeader = req.headers.authorization;

  if (!authHeader) {
    req.user = null;
    return next();
  }

  const parts = authHeader.split(' ');
  
  if (parts.length !== 2 || parts[0] !== 'Bearer') {
    req.user = null;
    return next();
  }

  const token = parts[1];

  try {
    const verificationKey = getVerificationKey();
    const decoded = jwt.verify(token, verificationKey, verifyOptions);

    req.user = {
      id: decoded.sub || decoded.userId,
      email: decoded.email,
      roles: decoded.roles || [],
      permissions: decoded.permissions || [],
      ...decoded
    };
  } catch (error) {
    req.user = null;
  }

  next();
};

const requireRole = (...roles) => {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Authentication required' });
    }

    const userRoles = req.user.roles || [];
    const hasRole = roles.some(role => userRoles.includes(role));

    if (!hasRole) {
      return res.status(403).json({ error: 'Insufficient permissions' });
    }

    next();
  };
};

const requirePermission = (...permissions) => {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Authentication required' });
    }

    const userPermissions = req.user.permissions || [];
    const hasPermission = permissions.some(permission => userPermissions.includes(permission));

    if (!hasPermission) {
      return res.status(403).json({ error: 'Insufficient permissions' });
    }

    next();
  };
};

